template <class T>
T sample( const T &x, unsigned int size, bool replace ) {
    // user's responsibility? // RNGScope scope;
    ans = Vector<T>(size);
    ans.index = IntegerVector(size);
    if ( replace ) {
        ... SampleReplace  ...
    } else {
        ... SampleNoReplace  ...
    }
    for (int ii = 0; ii<size; ii++ ) {
        ans[ii] = x[ ans.index[ii] ];
    }
}

